import React, { useState, useEffect } from 'react';
import { useTable } from 'react-table';

function PurchaseFunc() {
  const [purchases, setPurchases] = useState([]);
    
  useEffect(() => {
    fetchData();
  }, []);
  

  const fetchData = async () => {
    try {
      const response = await fetch('http://localhost:8081/PurchasesAPI');
      const data = await response.json();
      setPurchases(data);
    } catch (error) {
      console.log('Error fetching data:', error);
    }
  };
  
  const columns = [
    { Header: 'ID', accessor: 'id' },
    { Header: 'Location', accessor: 'location' },
    { Header: 'Material ID', accessor: 'materialid' },
    { Header: 'Quantity', accessor: 'quantity' },
    { Header: 'Date', accessor: 'date' },
  ];

  const tableInstance = useTable({ columns, data: purchases.length > 0 ? purchases : [] });

  const { getTableProps, getTableBodyProps, headerGroups, rows, prepareRow } = tableInstance;

  return (
    <div>
      <h1>My Purchases</h1>
      <table {...getTableProps()} style={{ border: '1px solid black' }}>
        <thead>
          {headerGroups.map(headerGroup => (
            <tr {...headerGroup.getHeaderGroupProps()} style={{ background: 'lightgray' }}>
              {headerGroup.headers.map(column => (
                <th {...column.getHeaderProps()} style={{ padding: '5px', border: '1px solid black' }}>
                  {column.render('Header')}
                </th>
              ))}
            </tr>
          ))}
        </thead>
        <tbody {...getTableBodyProps()}>
          {rows.map(row => {
            prepareRow(row);
            return (
              <tr {...row.getRowProps()}>
                {row.cells.map(cell => (
                  <td {...cell.getCellProps()} style={{ padding: '5px', border: '1px solid black' }}>
                    {cell.render('Cell')}
                  </td>
                ))}
              </tr>
            );
          })}
        </tbody>
      </table>
    </div>
  );
}

export default PurchaseFunc;
